  1→import { join } from "node:path";
  2→import { RPCHandler } from "@orpc/server/fetch";
  3→import { createAuth } from "./auth.js";
  4→import { db } from "./db.js";
  5→import { router } from "./router.js";
  6→
  7→const socialProviders: Record<
  8→	string,
  9→	{ clientId: string; clientSecret: string }
 10→> = {};
 11→if (process.env.GOOGLE_CLIENT_ID && process.env.GOOGLE_CLIENT_SECRET) {
 12→	socialProviders.google = {
 13→		clientId: process.env.GOOGLE_CLIENT_ID,
 14→		clientSecret: process.env.GOOGLE_CLIENT_SECRET,
 15→	};
 16→}
 17→if (process.env.GITHUB_CLIENT_ID && process.env.GITHUB_CLIENT_SECRET) {
 18→	socialProviders.github = {
 19→		clientId: process.env.GITHUB_CLIENT_ID,
 20→		clientSecret: process.env.GITHUB_CLIENT_SECRET,
 21→	};
 22→}
 23→
 24→const appURL = process.env.APP_URL ?? "http://localhost:4010";
 25→const trustedOrigins = process.env.TRUSTED_ORIGINS
 26→	? process.env.TRUSTED_ORIGINS.split(",").map((o) => o.trim())
 27→	: ["http://localhost:4011"];
 28→
 29→const auth = createAuth(db, {
 30→	appURL,
 31→	secret: process.env.BETTER_AUTH_SECRET,
 32→	socialProviders,
 33→	trustedOrigins,
 34→});
 35→
 36→const rpcHandler = new RPCHandler(router);
 37→
 38→const ALLOWED_ORIGIN = process.env.ALLOWED_ORIGIN ?? "http://localhost:4011";
 39→const STATIC_DIR = join(
 40→	import.meta.dir,
 41→	"..",
 42→	process.env.STATIC_DIR ?? "public",
 43→);
 44→
 45→function corsHeaders(origin: string | null): Record<string, string> {
 46→	if (origin !== ALLOWED_ORIGIN) return {};
 47→	return {
 48→		"Access-Control-Allow-Origin": ALLOWED_ORIGIN,
 49→		"Access-Control-Allow-Credentials": "true",
 50→		"Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
 51→		"Access-Control-Allow-Headers": "Content-Type, Authorization",
 52→	};
 53→}
 54→
 55→const port = process.env.PORT ?? 4010;
 56→
 57→const server = Bun.serve({
 58→	port,
 59→	async fetch(request) {
 60→		const origin = request.headers.get("Origin");
 61→		const cors = corsHeaders(origin);
 62→
 63→		if (request.method === "OPTIONS") {
 64→			return new Response(null, { status: 204, headers: cors });
 65→		}
 66→
 67→		const url = new URL(request.url);
 68→
 69→		if (url.pathname === "/api/cli-token") {
 70→			const session = await auth.api.getSession({
 71→				headers: request.headers,
 72→			});
 73→			if (!session) {
 74→				return new Response(JSON.stringify({ error: "Not authenticated" }), {
 75→					status: 401,
 76→					headers: { ...cors, "Content-Type": "application/json" },
 77→				});
 78→			}
 79→			return new Response(JSON.stringify({ token: session.session.token }), {
 80→				status: 200,
 81→				headers: { ...cors, "Content-Type": "application/json" },
 82→			});
 83→		}
 84→
 85→		if (url.pathname.startsWith("/api/auth")) {
 86→			const response = await auth.handler(request);
 87→			for (const [key, value] of Object.entries(cors)) {
 88→				response.headers.set(key, value);
 89→			}
 90→			return response;
 91→		}
 92→
 93→		const { matched, response } = await rpcHandler.handle(request, {
 94→			prefix: "/rpc",
 95→			context: await getContext(request),
 96→		});
 97→
 98→		if (matched) {
 99→			// Log 500 errors for debugging
100→			if (response.status >= 500) {
101→				const body = await response.clone().text();
102→				console.error(`[RPC ${url.pathname}] ${response.status}:`, body);
103→			}
104→			for (const [key, value] of Object.entries(cors)) {
105→				response.headers.set(key, value);
106→			}
107→			return response;
108→		}
109→
110→		// Static file serving (production: frontend assets)
111→		const filePath = join(STATIC_DIR, url.pathname);
112→		const file = Bun.file(filePath);
113→		if (await file.exists()) {
114→			return new Response(file);
115→		}
116→
117→		// SPA fallback: serve index.html for non-API routes
118→		const indexFile = Bun.file(join(STATIC_DIR, "index.html"));
119→		if (await indexFile.exists()) {
120→			return new Response(indexFile);
121→		}
122→
123→		return new Response("Not found", { status: 404, headers: cors });
124→	},
125→});
126→
127→async function getContext(request: Request) {
128→	const session = await auth.api.getSession({
129→		headers: request.headers,
130→	});
131→	return {
132→		user: session?.user ?? null,
133→		session: session?.session ?? null,
134→	};
135→}
136→
137→console.log(`API server listening on http://localhost:${server.port}`);
