 20→function getCliParams(): { cliCallback: string; state: string } | null {
 21→	const params = new URLSearchParams(window.location.search);
 22→	const cliCallback = params.get("cli_callback");
 23→	const state = params.get("state");
 24→	if (!cliCallback || !state) return null;
 25→	try {
 26→		const url = new URL(cliCallback);
 27→		if (url.hostname !== "127.0.0.1") return null;
 28→	} catch {
 29→		return null;
 30→	}
 31→	return { cliCallback, state };
 32→}
 33→
 34→function App() {
 35→	const { data: session, isPending } = authClient.useSession();
 36→	const [page, setPage] = useState<Page>("login");
 37→	const [cliRedirecting, setCliRedirecting] = useState(false);
 38→	const cliParams = getCliParams();
 39→
 40→	useEffect(() => {
 41→		if (!session || !cliParams || cliRedirecting) return;
 42→		setCliRedirecting(true);
 43→
 44→		fetch("/api/cli-token", { credentials: "include" })
 45→			.then((res) => res.json())
 46→			.then((data: { token: string }) => {
 47→				const redirectUrl = `${cliParams.cliCallback}?token=${encodeURIComponent(data.token)}&state=${encodeURIComponent(cliParams.state)}`;
 48→				window.location.href = redirectUrl;
 49→			});
 50→	}, [session, cliParams, cliRedirecting]);
 51→
 52→	if (isPending) {
 53→		return (
 54→			<div className="flex min-h-screen items-center justify-center">
 55→				<p className="text-muted-foreground">Loading...</p>
 56→			</div>
 57→		);
 58→	}
 59→
 60→	if (cliRedirecting) {
 61→		return (
 62→			<div className="flex min-h-screen items-center justify-center">
 63→				<p className="text-muted-foreground">Completing CLI login...</p>
 64→			</div>
 65→		);
 66→	}
 67→
 68→	if (!session) {
 69→		return (
 70→			<div className="flex min-h-screen items-center justify-center">
 71→				{page === "login" ? (
 72→					<LoginForm onSwitchToSignup={() => setPage("signup")} />
 73→				) : (
 74→					<SignupForm onSwitchToLogin={() => setPage("login")} />
 75→				)}
 76→			</div>
 77→		);
 78→	}
 79→
 80→	return (
 81→		<Routes>
 82→			<Route path="/" element={<Navigate to="/dashboard" replace />} />
 83→			<Route path="/dashboard" element={<DashboardLayout />}>
 84→				<Route index element={<OverviewPage />} />
