 92→/**
 93→ * Create a test user via better-auth sign-up and return a bearer token.
 94→ */
 95→export async function signUpTestUser(baseUrl: string): Promise<string> {
 96→	const res = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
 97→		method: "POST",
 98→		headers: { "Content-Type": "application/json" },
 99→		body: JSON.stringify({
100→			email: `test-${Date.now()}@example.com`,
101→			password: "test-password-123",
102→			name: "Test User",
103→		}),
104→	});
105→
106→	if (!res.ok) {
107→		const body = await res.text();
108→		throw new Error(`Sign-up failed (${res.status}): ${body}`);
109→	}
110→
111→	const data = (await res.json()) as { token?: string };
112→
113→	if (data.token) return data.token;
114→
115→	// Fallback: extract session token from set-cookie header
116→	const cookies = res.headers.getSetCookie();
117→	const sessionCookie = cookies
118→		.find((c) => c.startsWith("better-auth.session_token="))
119→		?.split("=")[1]
120→		?.split(";")[0];
121→
122→	if (sessionCookie) return sessionCookie;
123→
124→	throw new Error("Could not extract token from sign-up response");
125→}
