  1→import { randomBytes } from "node:crypto";
  2→import { buildCommand } from "@stricli/core";
  3→import { loadCredentials, saveCredentials } from "../lib/credentials.js";
  4→
  5→const DEFAULT_API_BASE = "https://app.rudel.ai";
  6→const DEFAULT_WEB_URL = "https://app.rudel.ai";
  7→const CALLBACK_TIMEOUT_MS = 120_000;
  8→
  9→async function runLogin(flags: {
 10→	apiBase: string;
 11→	webUrl: string;
 12→}): Promise<void> {
 13→	const write = (msg: string) => process.stdout.write(`${msg}\n`);
 14→	const writeError = (msg: string) => process.stderr.write(`${msg}\n`);
 15→
 16→	const existing = loadCredentials();
 17→	if (existing) {
 18→		write("Already logged in. Run `rudel logout` first to switch accounts.");
 19→		return;
 20→	}
 21→
 22→	const state = randomBytes(16).toString("hex");
 23→
 24→	let resolveCallback: (token: string) => void;
 25→	let rejectCallback: (error: Error) => void;
 26→	const tokenPromise = new Promise<string>((resolve, reject) => {
 27→		resolveCallback = resolve;
 28→		rejectCallback = reject;
 29→	});
 30→
 31→	const server = Bun.serve({
 32→		port: 0,
 33→		hostname: "127.0.0.1",
 34→		fetch(request) {
 35→			const url = new URL(request.url);
 36→			if (url.pathname !== "/callback") {
 37→				return new Response("Not found", { status: 404 });
 38→			}
 39→
 40→			const receivedToken = url.searchParams.get("token");
 41→			const receivedState = url.searchParams.get("state");
 42→
 43→			if (receivedState !== state) {
 44→				rejectCallback(new Error("State mismatch — possible CSRF attack"));
 45→				return new Response(
 46→					"<html><body><h1>Login failed</h1><p>State mismatch. Please try again.</p></body></html>",
 47→					{ headers: { "Content-Type": "text/html" } },
 48→				);
 49→			}
 50→
 51→			if (!receivedToken) {
 52→				rejectCallback(new Error("No token received"));
 53→				return new Response(
 54→					"<html><body><h1>Login failed</h1><p>No token received.</p></body></html>",
 55→					{ headers: { "Content-Type": "text/html" } },
 56→				);
 57→			}
 58→
 59→			resolveCallback(receivedToken);
 60→			return new Response(
 61→				"<html><body><h1>Login successful!</h1><p>You can close this tab and return to the terminal.</p></body></html>",
 62→				{ headers: { "Content-Type": "text/html" } },
 63→			);
 64→		},
 65→	});
 66→
 67→	const callbackUrl = `http://127.0.0.1:${server.port}/callback`;
 68→	const loginUrl = `${flags.webUrl}?cli_callback=${encodeURIComponent(callbackUrl)}&state=${state}`;
 69→
 70→	write("Opening browser for authentication...");
 71→	write(`If the browser doesn't open, visit: ${loginUrl}`);
 72→
 73→	// Open browser
 74→	if (process.platform === "win32") {
 75→		Bun.spawn(["cmd", "/c", "start", "", loginUrl], {
 76→			stdout: "ignore",
 77→			stderr: "ignore",
 78→		});
 79→	} else {
 80→		const opener = process.platform === "darwin" ? "open" : "xdg-open";
 81→		Bun.spawn([opener, loginUrl], { stdout: "ignore", stderr: "ignore" });
 82→	}
 83→
 84→	// Wait for callback with timeout
 85→	const timeout = setTimeout(() => {
 86→		rejectCallback(new Error("Login timed out after 120 seconds"));
 87→	}, CALLBACK_TIMEOUT_MS);
 88→
 89→	let token: string;
 90→	try {
 91→		token = await tokenPromise;
 92→	} catch (error) {
 93→		clearTimeout(timeout);
 94→		server.stop();
 95→		writeError(
 96→			`Login failed: ${error instanceof Error ? error.message : String(error)}`,
 97→		);
 98→		process.exitCode = 1;
 99→		return;
100→	}
101→	clearTimeout(timeout);
102→	server.stop();
103→
104→	// Validate token via /rpc/me
105→	write("Validating token...");
106→	const meResponse = await fetch(`${flags.apiBase}/rpc/me`, {
107→		method: "POST",
108→		headers: {
109→			"Content-Type": "application/json",
110→			Authorization: `Bearer ${token}`,
111→		},
112→		body: JSON.stringify({}),
113→	});
114→
115→	if (!meResponse.ok) {
116→		writeError("Login failed: token validation failed");
117→		process.exitCode = 1;
118→		return;
119→	}
120→
121→	const body = (await meResponse.json()) as {
122→		json: { id: string; email: string; name: string };
123→	};
124→
125→	saveCredentials(token, flags.apiBase);
126→	write(`Logged in as ${body.json.name} (${body.json.email})`);
127→}
128→
129→export const loginCommand = buildCommand({
130→	loader: async () => ({ default: runLogin }),
131→	parameters: {
132→		flags: {
133→			apiBase: {
134→				kind: "parsed",
135→				parse: String,
136→				brief: "API server base URL",
137→				default: DEFAULT_API_BASE,
138→			},
139→			webUrl: {
140→				kind: "parsed",
141→				parse: String,
142→				brief: "Web app URL for authentication",
143→				default: DEFAULT_WEB_URL,
144→			},
145→		},
146→	},
147→	docs: {
148→		brief: "Authenticate with the Rudel API via browser login",
149→	},
150→});
