  1→#!/usr/bin/env bun
  2→/**
  3→ * One-time migration script: Cloudflare D1 (SQLite) → Postgres (Neon)
  4→ *
  5→ * Prerequisites:
  6→ *   - `wrangler` CLI installed and authenticated
  7→ *   - PG_CONNECTION_STRING env var pointing to the target Postgres database
  8→ *
  9→ * Usage:
 10→ *   PG_CONNECTION_STRING=postgres://... bun run scripts/migrate-d1-to-pg.ts
 11→ *
 12→ * This script:
 13→ *   1. Exports all rows from the 4 auth tables in D1 via `wrangler d1 execute`
 14→ *   2. Transforms timestamps (integer ms → Date) and booleans (0/1 → true/false)
 15→ *   3. Inserts into Postgres in FK-safe order: user → session + account + verification
 16→ */
 17→
 18→import { execSync } from "node:child_process";
 19→import postgres from "postgres";
 20→
 21→const PG_CONNECTION_STRING = process.env.PG_CONNECTION_STRING;
 22→if (!PG_CONNECTION_STRING) {
 23→	console.error("PG_CONNECTION_STRING environment variable is required");
 24→	process.exit(1);
 25→}
 26→
 27→const D1_DATABASE_NAME = process.env.D1_DATABASE_NAME ?? "rudel";
 28→
 29→const sql = postgres(PG_CONNECTION_STRING);
 30→
 31→interface D1Result<T> {
 32→	success: boolean;
 33→	results: T[];
 34→}
 35→
 36→function queryD1<T>(query: string): T[] {
 37→	const raw = execSync(
 38→		`npx wrangler d1 execute ${D1_DATABASE_NAME} --remote --json --command="${query.replace(/"/g, '\\"')}"`,
 39→		{ encoding: "utf-8", maxBuffer: 50 * 1024 * 1024 },
 40→	);
 41→	const parsed = JSON.parse(raw) as D1Result<T>[];
 42→	return parsed[0]?.results ?? [];
 43→}
 44→
 45→function msToDate(ms: number | null): Date | null {
 46→	if (ms === null || ms === undefined) return null;
 47→	return new Date(ms);
 48→}
 49→
 50→function intToBool(val: number | null): boolean {
 51→	return val === 1;
 52→}
 53→
 54→// --- Export from D1 ---
 55→
 56→console.log("Exporting users from D1...");
 57→const d1Users = queryD1<Record<string, unknown>>("SELECT * FROM user");
 58→console.log(`  Found ${d1Users.length} users`);
 59→
 60→console.log("Exporting sessions from D1...");
 61→const d1Sessions = queryD1<Record<string, unknown>>("SELECT * FROM session");
 62→console.log(`  Found ${d1Sessions.length} sessions`);
 63→
 64→console.log("Exporting accounts from D1...");
 65→const d1Accounts = queryD1<Record<string, unknown>>("SELECT * FROM account");
 66→console.log(`  Found ${d1Accounts.length} accounts`);
 67→
 68→console.log("Exporting verifications from D1...");
 69→const d1Verifications = queryD1<Record<string, unknown>>(
 70→	"SELECT * FROM verification",
 71→);
 72→console.log(`  Found ${d1Verifications.length} verifications`);
 73→
 74→// --- Insert into Postgres (FK-safe order) ---
 75→
 76→console.log("\nInserting users into Postgres...");
 77→for (const u of d1Users) {
 78→	await sql`
 79→		INSERT INTO "user" (id, name, email, email_verified, image, created_at, updated_at)
 80→		VALUES (
 81→			${u.id as string},
 82→			${u.name as string},
 83→			${u.email as string},
 84→			${intToBool(u.email_verified as number)},
 85→			${(u.image as string) ?? null},
 86→			${msToDate(u.created_at as number)},
 87→			${msToDate(u.updated_at as number)}
 88→		)
 89→		ON CONFLICT (id) DO NOTHING
 90→	`;
 91→}
 92→console.log(`  Inserted ${d1Users.length} users`);
 93→
 94→console.log("Inserting sessions into Postgres...");
 95→for (const s of d1Sessions) {
 96→	await sql`
 97→		INSERT INTO "session" (id, expires_at, token, created_at, updated_at, ip_address, user_agent, user_id)
 98→		VALUES (
 99→			${s.id as string},
100→			${msToDate(s.expires_at as number)},
101→			${s.token as string},
102→			${msToDate(s.created_at as number)},
103→			${msToDate(s.updated_at as number)},
104→			${(s.ip_address as string) ?? null},
105→			${(s.user_agent as string) ?? null},
106→			${s.user_id as string}
107→		)
108→		ON CONFLICT (id) DO NOTHING
109→	`;
110→}
111→console.log(`  Inserted ${d1Sessions.length} sessions`);
112→
113→console.log("Inserting accounts into Postgres...");
114→for (const a of d1Accounts) {
115→	await sql`
116→		INSERT INTO "account" (id, account_id, provider_id, user_id, access_token, refresh_token, id_token, access_token_expires_at, refresh_token_expires_at, scope, password, created_at, updated_at)
117→		VALUES (
118→			${a.id as string},
119→			${a.account_id as string},
120→			${a.provider_id as string},
121→			${a.user_id as string},
122→			${(a.access_token as string) ?? null},
123→			${(a.refresh_token as string) ?? null},
124→			${(a.id_token as string) ?? null},
125→			${msToDate(a.access_token_expires_at as number)},
126→			${msToDate(a.refresh_token_expires_at as number)},
127→			${(a.scope as string) ?? null},
128→			${(a.password as string) ?? null},
129→			${msToDate(a.created_at as number)},
130→			${msToDate(a.updated_at as number)}
131→		)
132→		ON CONFLICT (id) DO NOTHING
133→	`;
134→}
135→console.log(`  Inserted ${d1Accounts.length} accounts`);
136→
137→console.log("Inserting verifications into Postgres...");
138→for (const v of d1Verifications) {
139→	await sql`
140→		INSERT INTO "verification" (id, identifier, value, expires_at, created_at, updated_at)
141→		VALUES (
142→			${v.id as string},
143→			${v.identifier as string},
144→			${v.value as string},
145→			${msToDate(v.expires_at as number)},
146→			${msToDate(v.created_at as number)},
147→			${msToDate(v.updated_at as number)}
148→		)
149→		ON CONFLICT (id) DO NOTHING
150→	`;
151→}
152→console.log(`  Inserted ${d1Verifications.length} verifications`);
153→
154→await sql.end();
155→console.log("\nMigration complete!");
